    @PostMapping("/simple/{topic}")
    public ResponseEntity<EventResponse> publishSimpleEvent(
            @PathVariable String topic,
            @RequestParam(required = false) String key,
            @RequestBody String payload,
            @RequestHeader Map<String, String> allHeaders) {

        try {
            // Filter and collect relevant custom headers (those starting with X- or known tracking headers)
            Map<String, String> kafkaHeaders = new HashMap<>();
            String effectiveTrackingId = UUID.randomUUID().toString();

            allHeaders.forEach((headerName, headerValue) -> {
                String lowerName = headerName.toLowerCase();
                if (lowerName.startsWith("x-") ||
                        lowerName.equals("tracking-id") ||
                        lowerName.equals("user-id") ||
                        lowerName.equals("session-id") ||
                        lowerName.equals("correlation-id")) {
                    kafkaHeaders.put(lowerName, headerValue);
                }
            });

            if (!kafkaHeaders.containsKey("tracking-id")) {
                kafkaHeaders.put("tracking-id", effectiveTrackingId);
            } else {
                effectiveTrackingId = kafkaHeaders.get("tracking-id");
            }

            String effectiveKey = key != null ? key : effectiveTrackingId;

            RecordMetadata metadata = kafkaEventProducer.sendEvent(topic, effectiveKey, payload, kafkaHeaders);

            EventResponse response = new EventResponse();
            response.setStatus("SUCCESS");
            response.setMessageId(effectiveTrackingId);
            response.setTopic(metadata.topic());
            response.setPartition(metadata.partition());
            response.setOffset(metadata.offset());
            response.setHeadersApplied(kafkaHeaders);

            return ResponseEntity.ok(response);

        } catch (ExecutionException | InterruptedException e) {
            Thread.currentThread().interrupt();
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("FAILED");
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
        }
    }
